import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

import { cacheTag } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: string;
};

const posts: Post[] = [
  {
    id: 'welcome',
    title: 'Welcome',
    body: 'This is the first cached post.',
    createdAt: new Date('2026-07-11T00:00:00.000Z').toISOString()
  }
];

export async function getPosts() {
  'use cache';

  cacheTag('posts');

  return posts;
}

export async function createPost(input: { title: string; body: string }) {
  const post: Post = {
    id: crypto.randomUUID(),
    title: input.title,
    body: input.body,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);

  return post;
}

'use server';

import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';

import { createPost } from '@/lib/posts';

export async function createPostAction(formData: FormData) {
  const title = String(formData.get('title') ?? '').trim();
  const body = String(formData.get('body') ?? '').trim();

  if (!title || !body) {
    throw new Error('Title and body are required.');
  }

  await createPost({ title, body });

  updateTag('posts');

  redirect('/');
}

import { createPostAction } from './actions';
import { getPosts } from '@/lib/posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem', maxWidth: '48rem', margin: '0 auto' }}>
      <h1>Posts</h1>
      <form action={createPostAction} style={{ display: 'grid', gap: '0.75rem', margin: '1.5rem 0' }}>
        <input name="title" placeholder="Title" required />
        <textarea name="body" placeholder="Body" required rows={5} />
        <button type="submit">Create post</button>
      </form>
      <section>
        <h2>Cached list</h2>
        <ul>
          {posts.map((post) => (
            <li key={post.id}>
              <strong>{post.title}</strong>
              <p>{post.body}</p>
            </li>
          ))}
        </ul>
      </section>
    </main>
  );
}

